/**
 * @name PlainPermissionManager deleteAccessConfig exact taint - accesskey to file write
 * @description Trace taint from accesskey parameter through deleteAccessConfig to any file write
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-accesskey-to-file-write
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module AccessKeyFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameter of deleteAccessConfig in PlainPermissionManager
    exists(Parameter p, Method m |
      m.hasName("deleteAccessConfig") and
      m.getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.plain", "PlainPermissionManager") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
    or
    // Parameter of updateGlobalWhiteAddrsConfig
    exists(Parameter p, Method m |
      m.hasName("updateGlobalWhiteAddrsConfig") and
      m.getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.plain", "PlainPermissionManager") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
    or
    // Parameter of updateAccessConfig
    exists(Parameter p, Method m |
      m.hasName("updateAccessConfig") and
      m.getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.plain", "PlainPermissionManager") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // writeDataObject in AclUtils - file path arg
    exists(MethodCall mc |
      mc.getMethod().hasName("writeDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // getYamlDataObject in AclUtils - file path arg  
    exists(MethodCall mc |
      mc.getMethod().hasName("getYamlDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // FileOutputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // Any file-related method call with tainted arg
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.plain", "PlainPermissionManager") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module AccessKeyFileFlow = TaintTracking::Global<AccessKeyFileConfig>;
import AccessKeyFileFlow::PathGraph

from AccessKeyFileFlow::PathNode source, AccessKeyFileFlow::PathNode sink
where AccessKeyFileFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ACL method param $@ flows to sink in PlainPermissionManager.", source.getNode(), "method parameter"

/**
 * @name RocketMQ network request to ACL file operation taint flow
 * @description Trace taint from RemotingCommand fields through AdminBrokerProcessor to ACL file operations
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-network-to-acl-file
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module AclFileTaintConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // RemotingCommand.getExtFields() or header field getters
    exists(MethodCall mc |
      source.asExpr() = mc and
      (
        (mc.getMethod().hasName("getExtFields") and
         mc.getQualifier().getType().(RefType).hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand"))
        or
        (mc.getMethod().hasName("decodeCommandCustomHeader") and
         mc.getQualifier().getType().(RefType).hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand"))
        or
        // Field getters on decoded headers (e.g., DeleteAccessConfigRequestHeader.getAccessKey())
        (mc.getMethod().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.common.protocol.header%") and
         mc.getMethod().getName().matches("get%"))
      )
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // PlainPermissionManager file operations
    exists(MethodCall mc |
      (mc.getMethod().hasName("deleteAccessConfig") or
       mc.getMethod().hasName("updateAccessConfig") or
       mc.getMethod().hasName("updateGlobalWhiteAddrsConfig")) and
      mc.getMethod().getDeclaringType().getPackage().getName().matches("org.apache.rocketmq.acl%") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Direct File construction
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // AclUtils.getYamlDataObject
    exists(MethodCall mc |
      mc.getMethod().hasName("getYamlDataObject") and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module AclFileTaintFlow = TaintTracking::Global<AclFileTaintConfig>;
import AclFileTaintFlow::PathGraph

from AclFileTaintFlow::PathNode source, AclFileTaintFlow::PathNode sink
where AclFileTaintFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: network request data $@ flows to ACL/file operation.", source.getNode(), "network request field"
